+#[derive(Default)]
+struct FromClauseCollationLookup {
+    col_map: Vec<(String, String, bool)>,
+    collations: Vec<Option<String>>,
+    using_skip_indices: HashSet<usize>,
+}
+
+struct SourceProjectionMeta {
+    visible_names: Vec<String>,
+    visible_indices: Vec<usize>,
+}
+
+fn build_from_clause_collation_lookup(
+    from: &FromClause,
+    schemas: &[TableSchema],
+) -> FromClauseCollationLookup {
+    let mut lookup = FromClauseCollationLookup::default();
+    collect_from_clause_collation_lookup(from, schemas, &mut lookup);
+    lookup
+}
+
+fn collect_from_clause_collation_lookup(
+    from: &FromClause,
+    schemas: &[TableSchema],
+    lookup: &mut FromClauseCollationLookup,
+) -> SourceProjectionMeta {
+    let mut left_meta = collect_table_or_subquery_collation_lookup(&from.source, schemas, lookup);
+    for join in &from.joins {
+        let right_meta = collect_table_or_subquery_collation_lookup(&join.table, schemas, lookup);
+        let using_cols = if join.join_type.natural {
+            right_meta
+                .visible_names
+                .iter()
+                .filter(|right_name| {
+                    left_meta
+                        .visible_names
+                        .iter()
+                        .any(|left_name| left_name.eq_ignore_ascii_case(right_name))
+                })
+                .cloned()
+                .collect::<Vec<_>>()
+        } else if let Some(JoinConstraint::Using(cols)) = join.constraint.as_ref() {
+            cols.clone()
+        } else {
+            Vec::new()
+        };
+
+        for (right_name, right_idx) in right_meta
+            .visible_names
+            .iter()
+            .zip(right_meta.visible_indices.iter().copied())
+        {
+            if using_cols
+                .iter()
+                .any(|using_col| using_col.eq_ignore_ascii_case(right_name))
+            {
+                lookup.using_skip_indices.insert(right_idx);
+            } else {
+                left_meta.visible_names.push(right_name.clone());
+                left_meta.visible_indices.push(right_idx);
+            }
+        }
+    }
+    left_meta
+}
+
+fn collect_table_or_subquery_collation_lookup(
+    source: &TableOrSubquery,
+    schemas: &[TableSchema],
+    lookup: &mut FromClauseCollationLookup,
+) -> SourceProjectionMeta {
+    if let TableOrSubquery::ParenJoin(from) = source {
+        return collect_from_clause_collation_lookup(from, schemas, lookup);
+    }
+
+    let column_names = expand_table_or_subquery_column_names(source, schemas);
+    let mut collations = table_or_subquery_result_collations(source, schemas);
+    collations.resize(column_names.len(), None);
+    collations.truncate(column_names.len());
+
+    let base_idx = lookup.col_map.len();
+    let label = source_projection_label(source).unwrap_or_default();
+    for (column_name, collation) in column_names.iter().zip(collations.iter()) {
+        lookup
+            .col_map
+            .push((label.clone(), column_name.clone(), false));
+        lookup.collations.push(collation.clone());
+    }
+
+    SourceProjectionMeta {
+        visible_names: column_names,
+        visible_indices: (0..collations.len())
+            .map(|offset| base_idx + offset)
+            .collect(),
+    }
+}
+
+fn select_expr_effective_collation(
+    expr: &Expr,
+    from_lookup: Option<&FromClauseCollationLookup>,
+    schemas: &[TableSchema],
+) -> Option<String> {
+    if let Expr::Collate { collation, .. } = expr {
+        return normalize_column_collation(Some(collation));
+    }
+    if let Expr::Column(col_ref, _) = expr {
+        if let Some(lookup) = from_lookup {
+            return resolve_from_clause_projection_collation(lookup, col_ref);
+        }
+        return agg_arg_collation(expr, schemas);
+    }
+    None
+}
+
+fn resolve_from_clause_projection_collation(
+    lookup: &FromClauseCollationLookup,
+    col_ref: &ColumnRef,
+) -> Option<String> {
+    let using_skip = if col_ref.table.is_none() && !lookup.using_skip_indices.is_empty() {
+        Some(&lookup.using_skip_indices)
+    } else {
+        None
+    };
+    let idx = find_col_in_map(
+        &lookup.col_map,
+        col_ref.table.as_deref(),
+        &col_ref.column,
+        using_skip,
+    )
+    .ok()?;
+    lookup.collations.get(idx).cloned().flatten()
+}
